import React, { useState } from 'react';
import axios from 'axios';
import './css/style.css'
function Auth({ setToken }) {
  const [isLogin, setIsLogin] = useState(true);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    const url = `http://localhost:5000/api/auth/${isLogin ? 'login' : 'register'}`;
    try {
      const res = await axios.post(url, { username, password });
      if (isLogin) setToken(res.data.token);
      else alert("Пользователь создан, теперь войдите");
    } catch (err) {
      alert("Ошибка аутентификации");
    }
  };

  return (
    <div style={{ padding: '50px', textAlign: 'center' }}>
      <h2>{isLogin ? 'Вход' : 'Регистрация'}</h2>
      <form onSubmit={handleSubmit}>
        <input placeholder="Username" onChange={e => setUsername(e.target.value)} /><br/>
        <input type="password" placeholder="Password" onChange={e => setPassword(e.target.value)} /><br/>
        <button type="submit">{isLogin ? 'Войти' : 'Создать аккаунт'}</button>
      </form>
      <button onClick={() => setIsLogin(!isLogin)} style={{ marginTop: '10px' }}>
        {isLogin ? 'Нет аккаунта? Регистрация' : 'Есть аккаунт? Войти'}
      </button>
    </div>
  );
}

export default Auth;
